package com.itwill.shop.cart;public class CartSQL {	public static final String CART_COUNT_BY_MEMBERID_PRODUCT_NO = "SELECT count(*) AS product_count FROM cart WHERE member_id = ? AND product_no = ?";	public static final String CART_INSERT = "INSERT INTO cart (cart_no, cart_qty, member_id, product_no) VALUES (cart_cart_no_SEQ.nextval, ?, ?, ?)";	public static final String CART_UPDATE_BY_MEMBERID_PRODUCT_NO = "UPDATE cart SET cart_qty = cart_qty + ? WHERE member_id = ? AND product_no = ?";	public static final String CART_UPDATE_BY_CART_NO = "UPDATE cart SET cart_qty = ? WHERE cart_no = ?";	public static final String CART_DELETE_BY_CART_NO = "DELETE FROM cart WHERE cart_no = ?";	public static final String CART_DELETE_BY_MEMBERID = "DELETE FROM cart WHERE member_id = ?";	public static final String CART_SELECT_BY_MEMBERID = "SELECT cart.cart_no, cart.member_id, product.product_no, product.product_img, product.product_name, cart.cart_qty, product.product_price FROM cart JOIN product ON cart.product_no = product.product_no WHERE member_id = ?";	public static final String CART_SELECT_BY_MEMBERID_LOGIC = "SELECT cart.*, product.* FROM cart join product ON cart.product_no = product.product_no WHERE member_id = ?";	public static final String CART_SELECT_BY_CART_NO = "SELECT product_no FROM cart WHERE cart_no = ?";}